'use client'

import { useState, useEffect } from 'react'
import { supabase } from '../../../lib/supabase'
import { Header } from '../../../components/layout/Header'
import { toast } from 'react-hot-toast'
import { 
  FiAlertCircle, 
  FiCheckCircle, 
  FiClock, 
  FiFilter,
  FiRefreshCw,
  FiBell,
  FiUserCheck,
  FiNavigation,
} from 'react-icons/fi'

interface Alert {
  id: string
  type: 'route' | 'user' | 'system' | 'payment'
  severity: 'high' | 'medium' | 'low'
  title: string
  message: string
  created_at: string
  resolved: boolean
  resolved_at?: string
  data?: any
}

export default function AlertsPage() {
  const [alerts, setAlerts] = useState<Alert[]>([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState('all')

  useEffect(() => {
    fetchAlerts()
    setupRealtimeSubscription()
  }, [filter])

  const fetchAlerts = async () => {
    try {
      setLoading(true)
      
      let query = supabase
        .from('alerts')
        .select('*')
        .order('created_at', { ascending: false })

      if (filter !== 'all') {
        if (filter === 'unresolved') {
          query = query.eq('resolved', false)
        } else {
          query = query.eq('type', filter)
        }
      }

      const { data, error } = await query

      if (error) throw error

      setAlerts(data || [])
    } catch (error) {
      toast.error('Failed to load alerts')
    } finally {
      setLoading(false)
    }
  }

  const setupRealtimeSubscription = () => {
    const subscription = supabase
      .channel('alerts-realtime')
      .on('postgres_changes', 
        { event: 'INSERT', schema: 'public', table: 'alerts' },
        (payload) => {
          toast.success(`New alert: ${payload.new.title}`)
          fetchAlerts()
        }
      )
      .subscribe()

    return () => subscription.unsubscribe()
  }

  const handleResolveAlert = async (alertId: string) => {
    try {
      const { error } = await supabase
        .from('alerts')
        .update({ 
          resolved: true,
          resolved_at: new Date().toISOString()
        })
        .eq('id', alertId)

      if (error) throw error
      
      toast.success('Alert resolved')
      fetchAlerts()
    } catch (error) {
      toast.error('Failed to resolve alert')
    }
  }

  const handleCheckNewRoutes = async () => {
    try {
      const { data: newRoutes } = await supabase
        .from('routes')
        .select('*')
        .eq('approved', false)
        .gte('created_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())

      if (newRoutes && newRoutes.length > 0) {
        // Create alerts for new routes
        const alerts = newRoutes.map(route => ({
          type: 'route' as const,
          severity: 'medium' as const,
          title: 'New Route Pending Approval',
          message: `Route "${route.name}" needs approval`,
          data: { route_id: route.id },
          resolved: false
        }))

        await supabase.from('alerts').insert(alerts)
        toast.success(`Created ${newRoutes.length} alert(s) for new routes`)
      } else {
        toast.success('No new routes found')
      }
    } catch (error) {
      toast.error('Failed to check for new routes')
    }
  }

  const handleCheckSystemHealth = async () => {
    try {
      // Check database connection
      const { error: dbError } = await supabase.from('users').select('count').limit(1)
      
      // Check if any services are down
      const services = [
        { name: 'Database', status: !dbError },
        { name: 'Authentication', status: true },
        { name: 'Realtime', status: true },
        { name: 'Storage', status: true }
      ]

      const downServices = services.filter(s => !s.status)
      
      if (downServices.length > 0) {
        await supabase.from('alerts').insert({
          type: 'system',
          severity: 'high',
          title: 'Service Disruption',
          message: `${downServices.length} service(s) are down`,
          data: { services: downServices },
          resolved: false
        })
        
        toast.error(`${downServices.length} service(s) are down`)
      } else {
        toast.success('All systems operational')
      }
    } catch (error) {
      toast.error('Failed to check system health')
    }
  }

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'high': return 'bg-error/10 text-error border-error/20'
      case 'medium': return 'bg-yellow-100 text-yellow-800 border-yellow-200'
      case 'low': return 'bg-blue-100 text-blue-800 border-blue-200'
      default: return 'bg-gray-100 text-gray-800 border-gray-200'
    }
  }

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'route': return <FiNavigation className="mr-2" />
      case 'user': return <FiUserCheck className="mr-2" />
      case 'system': return <FiAlertCircle className="mr-2" />
      case 'payment': return <FiBell className="mr-2" />
      default: return <FiAlertCircle className="mr-2" />
    }
  }

  return (
    <div className="space-y-6">
      <Header 
        title="Alerts & Monitoring" 
        subtitle="Monitor system alerts, route submissions, and user activities"
      />

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 space-y-6">
          <div className="bg-white rounded-lg shadow p-6">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center space-x-4">
                <select
                  value={filter}
                  onChange={(e) => setFilter(e.target.value)}
                  className="px-4 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
                >
                  <option value="all">All Alerts</option>
                  <option value="unresolved">Unresolved</option>
                  <option value="route">Route Alerts</option>
                  <option value="user">User Alerts</option>
                  <option value="system">System Alerts</option>
                  <option value="payment">Payment Alerts</option>
                </select>
              </div>

              <div className="flex items-center space-x-3">
                <button
                  onClick={handleCheckNewRoutes}
                  className="flex items-center space-x-2 px-4 py-2 border border-border rounded-lg hover:bg-gray-50"
                >
                  <FiRefreshCw />
                  <span>Check New Routes</span>
                </button>
                
                <button
                  onClick={handleCheckSystemHealth}
                  className="flex items-center space-x-2 px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark"
                >
                  <FiAlertCircle />
                  <span>System Check</span>
                </button>
              </div>
            </div>

            <div className="space-y-4">
              {loading ? (
                <div className="text-center py-12">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
                  <p className="mt-2 text-text-light">Loading alerts...</p>
                </div>
              ) : alerts.length === 0 ? (
                <div className="text-center py-12">
                  <FiCheckCircle className="text-success mx-auto text-4xl mb-4" />
                  <p className="text-text">No alerts found</p>
                  <p className="text-text-light">All systems are running smoothly</p>
                </div>
              ) : (
                alerts.map(alert => (
                  <div
                    key={alert.id}
                    className={`border rounded-lg p-4 ${alert.resolved ? 'bg-gray-50' : ''}`}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex items-start">
                        <div className={`p-2 rounded-lg ${getSeverityColor(alert.severity)} mr-4`}>
                          {getTypeIcon(alert.type)}
                        </div>
                        <div>
                          <div className="flex items-center space-x-3">
                            <h4 className="font-semibold text-text">{alert.title}</h4>
                            <span className={`text-xs px-2 py-1 rounded-full ${getSeverityColor(alert.severity)}`}>
                              {alert.severity.toUpperCase()}
                            </span>
                            {alert.resolved && (
                              <span className="text-xs px-2 py-1 bg-success/10 text-success rounded-full">
                                RESOLVED
                              </span>
                            )}
                          </div>
                          <p className="text-text-light mt-1">{alert.message}</p>
                          <div className="flex items-center space-x-4 mt-2">
                            <span className="text-xs text-text-light flex items-center">
                              <FiClock className="mr-1" />
                              {new Date(alert.created_at).toLocaleString()}
                            </span>
                            <span className="text-xs text-text-light">
                              {alert.type.toUpperCase()}
                            </span>
                          </div>
                        </div>
                      </div>
                      
                      {!alert.resolved && (
                        <button
                          onClick={() => handleResolveAlert(alert.id)}
                          className="px-3 py-1 bg-success text-white rounded-lg hover:bg-success/90 text-sm"
                        >
                          Mark Resolved
                        </button>
                      )}
                    </div>
                    
                    {alert.data && (
                      <div className="mt-3 ml-12">
                        <details className="text-sm">
                          <summary className="cursor-pointer text-primary hover:text-primary-dark">
                            View Details
                          </summary>
                          <pre className="mt-2 p-3 bg-gray-50 rounded text-xs overflow-x-auto">
                            {JSON.stringify(alert.data, null, 2)}
                          </pre>
                        </details>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>

          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-text mb-4">Alert Statistics</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="p-4 bg-red-50 rounded-lg">
                <p className="text-sm text-text-light">High Priority</p>
                <p className="text-2xl font-bold text-error">
                  {alerts.filter(a => a.severity === 'high' && !a.resolved).length}
                </p>
              </div>
              <div className="p-4 bg-yellow-50 rounded-lg">
                <p className="text-sm text-text-light">Medium Priority</p>
                <p className="text-2xl font-bold text-yellow-600">
                  {alerts.filter(a => a.severity === 'medium' && !a.resolved).length}
                </p>
              </div>
              <div className="p-4 bg-blue-50 rounded-lg">
                <p className="text-sm text-text-light">Unresolved</p>
                <p className="text-2xl font-bold text-text">
                  {alerts.filter(a => !a.resolved).length}
                </p>
              </div>
              <div className="p-4 bg-green-50 rounded-lg">
                <p className="text-sm text-text-light">Resolved Today</p>
                <p className="text-2xl font-bold text-success">
                  {alerts.filter(a => a.resolved && 
                    new Date(a.resolved_at || '').toDateString() === new Date().toDateString()
                  ).length}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-semibold text-text mb-4">Quick Actions</h3>
            <div className="space-y-3">
              <button className="w-full px-4 py-3 border border-border rounded-lg hover:bg-gray-50 text-left">
                Configure Alert Rules
              </button>
              <button className="w-full px-4 py-3 border border-border rounded-lg hover:bg-gray-50 text-left">
                View Alert History
              </button>
              <button className="w-full px-4 py-3 border border-border rounded-lg hover:bg-gray-50 text-left">
                Export Alerts
              </button>
            </div>
          </div>

          <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-semibold text-text mb-4">Alert Types</h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between p-3 bg-red-50 rounded">
                <div className="flex items-center">
                  <div className="w-3 h-3 bg-error rounded-full mr-3"></div>
                  <span>High Priority</span>
                </div>
                <span className="font-medium text-error">
                  {alerts.filter(a => a.severity === 'high').length}
                </span>
              </div>
              <div className="flex items-center justify-between p-3 bg-yellow-50 rounded">
                <div className="flex items-center">
                  <div className="w-3 h-3 bg-yellow-500 rounded-full mr-3"></div>
                  <span>Medium Priority</span>
                </div>
                <span className="font-medium text-yellow-600">
                  {alerts.filter(a => a.severity === 'medium').length}
                </span>
              </div>
              <div className="flex items-center justify-between p-3 bg-blue-50 rounded">
                <div className="flex items-center">
                  <div className="w-3 h-3 bg-blue-500 rounded-full mr-3"></div>
                  <span>Low Priority</span>
                </div>
                <span className="font-medium text-blue-600">
                  {alerts.filter(a => a.severity === 'low').length}
                </span>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-lg shadow">
            <h3 className="text-lg font-semibold text-text mb-4">Common Issues</h3>
            <div className="space-y-3">
              <div className="p-3 border border-border rounded-lg">
                <p className="font-medium text-text">New Route Submissions</p>
                <p className="text-sm text-text-light">Check every 2 hours</p>
              </div>
              <div className="p-3 border border-border rounded-lg">
                <p className="font-medium text-text">Payment Failures</p>
                <p className="text-sm text-text-light">Monitor real-time</p>
              </div>
              <div className="p-3 border border-border rounded-lg">
                <p className="font-medium text-text">System Errors</p>
                <p className="text-sm text-text-light">Check logs hourly</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}